    self.conn = sqlite3.connect(":memory:")
    self.cursor = self.conn.cursor()

  def create(self,name):
    self.cursor.execute(
			"CREATE TABLE IF NOT EXISTS Models (name TEXT)"
		)
    self.cursor.execute(
			"INSERT INTO Models(name) VALUES (?)",
			(name,),
		)
